  1→import { distance } from '@/geometry/point';
  2→import { doorOutlineOnWall, windowOutlineOnWall, wallLength, projectPointOnWall } from '@/geometry/wallGeometry';
  3→import { pointInPolygon } from '@/geometry/polygon';
  4→import { columnOutline } from '@/geometry/columnGeometry';
  5→import { getBeamRenderData } from '@/geometry/beamGeometry';
  6→import { getStairRenderData } from '@/geometry/stairGeometry';
  7→import { landingContainsPoint } from '@/geometry/landingGeometry';
  8→import { slabContainsPoint } from '@/geometry/slabGeometry';
  9→import { hitTestAnnotation } from '@/annotations/scene';
 10→import { MIN_WALL_LENGTH, SNAP_DISTANCE_PX } from '@/domain/defaults';
 11→import { getWallRenderData, resolveWallEndpoints, snapWallEndpoint } from '@/geometry/wallColumnGeometry';
 12→import { duplicateColumn } from '@/domain/columnModels';
 13→import { hitTestSectionCut } from '@/geometry/sectionCutGeometry';
 14→import { collectPlanRegionSelection, normalizeRectBounds, rectSize } from '@/clipboard/planClipboard';
 15→
 16→function hitTest(modelPos, floor, annotationTolerance) {
 17→  // Hit test doors first (smaller targets, higher priority)
 18→  for (const door of floor.doors) {
 19→    const wall = floor.walls.find(w => w.id === door.wallId);
 20→    if (!wall) continue;
 21→    const info = doorOutlineOnWall(wall, door);
 22→    const poly = [info.p1, info.p2, info.p3, info.p4];
 23→    if (pointInPolygon(modelPos, poly)) {
 24→      return { id: door.id, type: 'door' };
 25→    }
 26→  }
 27→
 28→  // Hit test windows
 29→  for (const win of floor.windows) {
 30→    const wall = floor.walls.find(w => w.id === win.wallId);
 31→    if (!wall) continue;
 32→    const info = windowOutlineOnWall(wall, win);
 33→    const poly = [info.p1, info.p2, info.p3, info.p4];
 34→    if (pointInPolygon(modelPos, poly)) {
 35→      return { id: win.id, type: 'window' };
 36→    }
 37→  }
 38→
 39→  // Hit test walls
 40→  // Hit test columns
 41→  for (const sc of (floor.sectionCuts || [])) {
 42→    if (hitTestSectionCut(modelPos, sc, annotationTolerance)) {
 43→      return { id: sc.id, type: 'sectionCut' };
 44→    }
 45→  }
 46→
 47→  for (const column of (floor.columns || [])) {
 48→    const outline = columnOutline(column);
 49→    if (pointInPolygon(modelPos, outline)) {
 50→      return { id: column.id, type: 'column' };
 51→    }
 52→  }
 53→
 54→  // Hit test beams
 55→  for (const beam of (floor.beams || [])) {
 56→    const renderData = getBeamRenderData(beam, floor.columns || []);
 57→    if (!renderData) continue;
 58→    if (pointInPolygon(modelPos, renderData.outline)) {
 59→      return { id: beam.id, type: 'beam' };
 60→    }
 61→  }
 62→
 63→  // Hit test walls
 64→  for (const wall of floor.walls) {
 65→    const outline = getWallRenderData(wall, floor.columns || []).outline;
 66→    if (pointInPolygon(modelPos, outline)) {
 67→      return { id: wall.id, type: 'wall' };
 68→    }
 69→  }
 70→
 71→  // Hit test stairs after walls/beams/columns so current editing priority stays intact.
 72→  for (const stair of (floor.stairs || [])) {
 73→    const renderData = getStairRenderData(stair);
 74→    if (!renderData) continue;
 75→    if (pointInPolygon(modelPos, renderData.outline)) {
 76→      return { id: stair.id, type: 'stair' };
 77→    }
 78→  }
 79→
 80→  // Hit test landings
 81→  for (const landing of (floor.landings || [])) {
 82→    if (landingContainsPoint(landing, modelPos)) {
 83→      return { id: landing.id, type: 'landing' };
 84→    }
 85→  }
 86→
 87→  // Hit test rooms (lowest priority)
 88→  for (const room of floor.rooms) {
 89→    if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
 90→      return { id: room.id, type: 'room' };
 91→    }
 92→  }
 93→
 94→  for (const slab of (floor.slabs || [])) {
 95→    if (slabContainsPoint(slab, modelPos)) {
 96→      return { id: slab.id, type: 'slab' };
 97→    }
 98→  }
 99→
100→  const annotationHit = hitTestAnnotation(modelPos, floor, annotationTolerance);
101→  if (annotationHit) {
102→    return annotationHit;
103→  }
104→
105→  return null;
106→}
107→
108→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
109→  return {
110→    onMouseDown(modelPos, e, toolState) {
111→      if (e.button !== 0) return;
112→
113→      const floor = getFloor(activeFloorId);
114→      if (!floor) return;
115→
116→      // Check if clicking a handle
117→      const target = e.target;
118→      if (target.dataset.handle) {
119→        editorDispatch({
120→          type: 'UPDATE_TOOL_STATE',
121→          payload: {
122→            dragging: true,
123→            dragType: 'handle',
124→            handle: target.dataset.handle,
125→            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
126→            startPos: modelPos,
127→          },
128→        });
129→        return;
130→      }
131→
132→      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
133→      if (hit) {
134→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
135→        const draggableTypes = new Set(['wall', 'column', 'door', 'window', 'stair', 'sectionCut', 'landing']);
136→        if (!draggableTypes.has(hit.type)) return;
137→        editorDispatch({
138→          type: 'UPDATE_TOOL_STATE',
139→          payload: {
140→            dragging: true,
141→            dragType: 'move',
142→            startPos: modelPos,
143→            originalPos: modelPos,
144→          },
145→        });
146→      } else {
147→        editorDispatch({
148→          type: 'UPDATE_TOOL_STATE',
149→          payload: {
150→            dragging: true,
151→            dragType: 'marquee',
152→            startPos: modelPos,
153→            currentPos: modelPos,
154→          },
155→        });
156→      }
157→    },
158→
159→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
160→      if (toolState.dragging && toolState.dragType === 'marquee') {
161→        editorDispatch({
162→          type: 'UPDATE_TOOL_STATE',
163→          payload: { currentPos: modelPos },
164→        });
165→        return;
166→      }
167→
168→      if (!toolState.dragging || !selectedId) return;
169→
170→      const floor = getFloor(activeFloorId);
171→      if (!floor) return;
172→      const dx = modelPos.x - toolState.startPos.x;
173→      const dy = modelPos.y - toolState.startPos.y;
174→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
175→
176→      if (selectedType === 'wall') {
177→        const wall = floor.walls.find(w => w.id === selectedId);
178→        if (!wall) return;
179→        const resolved = resolveWallEndpoints(wall, floor.columns || []);
180→
181→        if (toolState.dragType === 'handle') {
182→          const handle = toolState.handle;
183→          const oppositeKey = handle === 'start' ? 'end' : 'start';
184→          const oppositePoint = resolved[oppositeKey];
185→          let nextPoint = modelPos;
186→          let nextAttachment = null;
187→
188→          if (e.shiftKey) {
189→            const dx = modelPos.x - oppositePoint.x;
190→            const dy = modelPos.y - oppositePoint.y;
191→            const angle = Math.atan2(dy, dx);
192→            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
193→            const len = Math.sqrt(dx * dx + dy * dy);
194→            nextPoint = {
195→              x: oppositePoint.x + Math.cos(snapAngle) * len,
196→              y: oppositePoint.y + Math.sin(snapAngle) * len,
197→            };
198→          } else if (snapEnabled) {
199→            const snapResult = snapWallEndpoint(modelPos, {
200→              walls: floor.walls,
201→              columns: floor.columns || [],
202→              snapDist: snapDistModel,
203→              otherPoint: oppositePoint,
204→              ignoreWallId: wall.id,
205→            });
206→            if (snapResult) {
207→              nextPoint = snapResult.point;
208→              nextAttachment = snapResult.attachment;
209→            }
210→          }
211→
212→          if (distance(nextPoint, oppositePoint) < MIN_WALL_LENGTH) return;
213→
214→          dispatch({
215→            type: 'WALL_UPDATE',
216→            floorId: activeFloorId,
217→            wall: {
218→              id: wall.id,
219→              [handle]: nextPoint,
220→              [`${handle}Attachment`]: nextAttachment,
221→            },
222→          });
223→        } else {
224→          let nextStart = { x: resolved.start.x + dx, y: resolved.start.y + dy };
225→          let nextEnd = { x: resolved.end.x + dx, y: resolved.end.y + dy };
226→          let startAttachment = null;
227→          let endAttachment = null;
228→
229→          if (snapEnabled) {
230→            const startSnap = snapWallEndpoint(nextStart, {
231→              walls: floor.walls,
232→              columns: floor.columns || [],
233→              snapDist: snapDistModel,
234→              otherPoint: nextEnd,
235→              ignoreWallId: wall.id,
236→            });
237→            if (startSnap) {
238→              nextStart = startSnap.point;
239→              startAttachment = startSnap.attachment;
240→            }
241→
242→            const endSnap = snapWallEndpoint(nextEnd, {
243→              walls: floor.walls,
244→              columns: floor.columns || [],
245→              snapDist: snapDistModel,
246→              otherPoint: nextStart,
247→              ignoreWallId: wall.id,
248→            });
249→            if (endSnap) {
250→              nextEnd = endSnap.point;
251→              endAttachment = endSnap.attachment;
252→            }
253→          }
254→
255→          if (distance(nextStart, nextEnd) < MIN_WALL_LENGTH) return;
256→
257→          dispatch({
258→            type: 'WALL_UPDATE',
259→            floorId: activeFloorId,
260→            wall: {
261→              id: wall.id,
262→              start: nextStart,
263→              end: nextEnd,
264→              startAttachment,
265→              endAttachment,
266→            },
267→          });
268→        }
269→        editorDispatch({
270→          type: 'UPDATE_TOOL_STATE',
271→          payload: { startPos: modelPos },
272→        });
273→      } else if (selectedType === 'column') {
274→        const col = (floor.columns || []).find(c => c.id === selectedId);
275→        if (!col) return;
276→        dispatch({
277→          type: 'COLUMN_UPDATE',
278→          floorId: activeFloorId,
279→          column: { id: col.id, x: col.x + dx, y: col.y + dy },
280→        });
281→        editorDispatch({
282→          type: 'UPDATE_TOOL_STATE',
283→          payload: { startPos: modelPos },
284→        });
285→      } else if (selectedType === 'sectionCut') {
286→        const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId);
287→        if (!sectionCut) return;
288→
289→        if (toolState.dragType === 'handle') {
290→          const handle = toolState.handle;
291→          const nextSectionCut = handle === 'start'
292→            ? { ...sectionCut, startPoint: modelPos }
293→            : { ...sectionCut, endPoint: modelPos };
294→
295→          if (distance(nextSectionCut.startPoint, nextSectionCut.endPoint) < MIN_WALL_LENGTH) return;
296→
297→          dispatch({
298→            type: 'SECTION_UPDATE',
299→            floorId: activeFloorId,
300→            sectionCut: nextSectionCut,
301→          });
302→        } else {
303→          dispatch({
304→            type: 'SECTION_UPDATE',
305→            floorId: activeFloorId,
306→            sectionCut: {
307→              id: sectionCut.id,
308→              startPoint: {
309→                x: sectionCut.startPoint.x + dx,
310→                y: sectionCut.startPoint.y + dy,
311→              },
312→              endPoint: {
313→                x: sectionCut.endPoint.x + dx,
314→                y: sectionCut.endPoint.y + dy,
315→              },
316→            },
