import { columnOutline } from '@/geometry/columnGeometry';
import { getBeamRenderData } from '@/geometry/beamGeometry';
import { getLandingRenderData } from '@/geometry/landingGeometry';
import { getStairRenderData } from '@/geometry/stairGeometry';
import { getSlabRenderData } from '@/geometry/slabGeometry';
import { getWallRenderData } from '@/geometry/wallColumnGeometry';
import { getManualAnnotationFigure } from '@/annotations/scene';
import { getSectionCutRenderData } from '@/geometry/sectionCutGeometry';

const HANDLE_SIZE = 8; // px, will use vectorEffect

function WallSelection({ wall, columns, zoom }) {
  const outline = getWallRenderData(wall, columns || []).outline;
  const points = outline.map(p => `${p.x},${p.y}`).join(' ');
  const handleR = HANDLE_SIZE / zoom;

  return (
    <g>
      <polygon
        points={points}
        fill="var(--color-selection-fill)"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
      {/* Endpoint handles */}
      <rect
        data-handle="start"
        x={wall.start.x - handleR / 2}
        y={wall.start.y - handleR / 2}
        width={handleR}
        height={handleR}
        fill="white"
        stroke="var(--color-selection)"
        strokeWidth={2}
        vectorEffect="non-scaling-stroke"
        style={{ cursor: 'move' }}
      />
      <rect
        data-handle="end"
        x={wall.end.x - handleR / 2}
        y={wall.end.y - handleR / 2}
        width={handleR}
        height={handleR}
        fill="white"
        stroke="var(--color-selection)"
        strokeWidth={2}
        vectorEffect="non-scaling-stroke"
        style={{ cursor: 'move' }}
      />
    </g>
  );
}

export default function SelectionOverlay({ selectedId, selectedType, floor, zoom }) {
  if (!selectedId || !floor) return null;

  if (selectedType === 'slab') {
    const slab = (floor.slabs || []).find(s => s.id === selectedId) || null;
    const renderData = slab ? getSlabRenderData(slab) : null;
    if (!renderData) return null;

    const handleR = HANDLE_SIZE / zoom;
    return (
      <g>
        <polygon
          points={renderData.points}
          fill="var(--color-selection-fill)"
          stroke="var(--color-selection)"
          strokeWidth={2}
          strokeDasharray="6 3"
          vectorEffect="non-scaling-stroke"
        />
        {renderData.outline.map((point, index) => (
          <rect
            key={`${point.x}-${point.y}-${index}`}
            data-handle="slab-vertex"
            data-index={index}
            x={point.x - handleR / 2}
            y={point.y - handleR / 2}
            width={handleR}
            height={handleR}
            fill="white"
            stroke="var(--color-selection)"
            strokeWidth={2}
            vectorEffect="non-scaling-stroke"
            style={{ cursor: 'move' }}
          />
        ))}
      </g>
    );
  }

  if (selectedType === 'wall') {
    const wall = floor.walls.find(w => w.id === selectedId);
    if (!wall) return null;
    return <WallSelection wall={wall} columns={floor.columns || []} zoom={zoom} />;
  }

  if (selectedType === 'sectionCut') {
    const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId) || null;
    const renderData = getSectionCutRenderData(sectionCut);
    if (!renderData) return null;
    const handleR = HANDLE_SIZE / zoom;

    return (
      <g>
        <line
          x1={renderData.line.start.x}
          y1={renderData.line.start.y}
          x2={renderData.line.end.x}
          y2={renderData.line.end.y}
          stroke="var(--color-selection)"
          strokeWidth={2}
          strokeDasharray="6 3"
          vectorEffect="non-scaling-stroke"
        />
        <rect
          data-handle="start"
          x={sectionCut.startPoint.x - handleR / 2}
          y={sectionCut.startPoint.y - handleR / 2}
          width={handleR}
          height={handleR}
          fill="white"
          stroke="var(--color-selection)"
          strokeWidth={2}
          vectorEffect="non-scaling-stroke"
          style={{ cursor: 'move' }}
        />
        <rect
          data-handle="end"
          x={sectionCut.endPoint.x - handleR / 2}
          y={sectionCut.endPoint.y - handleR / 2}
          width={handleR}
          height={handleR}
          fill="white"
          stroke="var(--color-selection)"
          strokeWidth={2}
          vectorEffect="non-scaling-stroke"
          style={{ cursor: 'move' }}
        />
      </g>
    );
  }

  if (selectedType === 'annotation') {
    const figure = getManualAnnotationFigure(floor, selectedId);
    if (!figure) return null;
    return (
      <g>
        {figure.extensionLines.map((line, index) => (
          <line
            key={`annotation-ext-${index}`}
            x1={line.start.x}
            y1={line.start.y}
            x2={line.end.x}
            y2={line.end.y}
            stroke="var(--color-selection)"
            strokeWidth={2}
            strokeDasharray="6 3"
            vectorEffect="non-scaling-stroke"
          />
        ))}
        <line
          x1={figure.lineStart.x}
          y1={figure.lineStart.y}
          x2={figure.lineEnd.x}
          y2={figure.lineEnd.y}
          stroke="var(--color-selection)"
          strokeWidth={2}
          strokeDasharray="6 3"
          vectorEffect="non-scaling-stroke"
        />
      </g>
    );
  }

  if (selectedType === 'door') {
    const door = floor.doors.find(d => d.id === selectedId);
    if (!door) return null;
    const wall = floor.walls.find(w => w.id === door.wallId);
    if (!wall) return null;
    // Highlight parent wall subtly
    const outline = getWallRenderData(wall, floor.columns || []).outline;
    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="none"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  if (selectedType === 'beam') {
    const beam = (floor.beams || []).find(b => b.id === selectedId);
    if (!beam) return null;
    const renderData = getBeamRenderData(beam, floor.columns || []);
    if (!renderData) return null;
    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="var(--color-selection-fill)"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  if (selectedType === 'stair') {
    const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
    if (!stair) return null;
    const renderData = getStairRenderData(stair);
    if (!renderData) return null;
    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="var(--color-selection-fill)"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  if (selectedType === 'landing') {
    const landing = (floor.landings || []).find(l => l.id === selectedId);
    if (!landing) return null;
    const renderData = getLandingRenderData(landing);
    if (!renderData) return null;
    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="var(--color-selection-fill)"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  if (selectedType === 'window') {
    const win = floor.windows.find(w => w.id === selectedId);
    if (!win) return null;
    const wall = floor.walls.find(w => w.id === win.wallId);
    if (!wall) return null;
    const outline = getWallRenderData(wall, floor.columns || []).outline;
    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="none"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  if (selectedType === 'column') {
    const column = (floor.columns || []).find(c => c.id === selectedId);
    if (!column) return null;
    const outline = columnOutline(column);
    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
    const handleR = HANDLE_SIZE / zoom;
    return (
      <g>
        <polygon
          points={points}
          fill="var(--color-selection-fill)"
          stroke="var(--color-selection)"
          strokeWidth={2}
          strokeDasharray="6 3"
          vectorEffect="non-scaling-stroke"
        />
        {outline.map((p, i) => (
          <rect
            key={i}
            x={p.x - handleR / 2}
            y={p.y - handleR / 2}
            width={handleR}
            height={handleR}
            fill="white"
            stroke="var(--color-selection)"
            strokeWidth={2}
            vectorEffect="non-scaling-stroke"
            style={{ cursor: 'move' }}
          />
        ))}
      </g>
    );
  }

  if (selectedType === 'room') {
    const room = floor.rooms.find(r => r.id === selectedId);
    if (!room?.points?.length) return null;
    const points = room.points.map(p => `${p.x},${p.y}`).join(' ');
    return (
      <polygon
        points={points}
        fill="none"
        stroke="var(--color-selection)"
        strokeWidth={2}
        strokeDasharray="6 3"
        vectorEffect="non-scaling-stroke"
      />
    );
  }

  return null;
}

import { useEffect, useRef, useState } from 'react';
import { useProject } from '@/app/ProjectProvider';
import { useEditor } from '@/app/EditorProvider';
import { getAnnotationDisplayLabel } from '@/annotations/format';
import { getBeamDisplayLabel } from '@/domain/beamLabels';
import { getDefaultActiveFloorId, getFloorElevation, getFloorLevelIndex, getFloorToFloorHeight, getOrderedFloors } from '@/domain/floorModels';
import { getSlabDisplayLabel } from '@/domain/slabLabels';
import { getStairDisplayLabel } from '@/domain/stairLabels';
import { createSheetViewport } from '@/domain/sheetModels';
import { exportActiveSheetAsPdf, exportActiveSheetAsPng } from '@/export/sheetExport';
import { wallLength } from '@/geometry/wallGeometry';
import { getColumnAutoLabel, getColumnListLabel } from '@/domain/columnLabels';
import { duplicateColumn } from '@/domain/columnModels';
import { beamLength } from '@/geometry/beamGeometry';
import { slabArea } from '@/geometry/slabGeometry';
import { stairRun, stairTotalRise } from '@/geometry/stairGeometry';
import { computeLandingElevation } from '@/geometry/landingGeometry';
import { getLandingDisplayLabel } from '@/domain/landingLabels';
import { sectionCutLength } from '@/geometry/sectionCutGeometry';
import { getManualAnnotationFigure } from '@/annotations/scene';
import { fitViewportToSheet, getDefaultViewportRect } from '@/sheets/layout';
import { listPaperPresets } from '@/sheets/paper';
import { getViewportSourceLabel, resolveSheetViewportSource } from '@/sheets/sources';
import InputField from './InputField';
import styles from './PropertiesPanel.module.css';

function useUnits() {
  const [unit, setUnit] = useState('mm');
  const isMm = unit === 'mm';
  return {
    unit,
    setUnit,
    suffix: isMm ? 'mm' : 'm',
    toDisplay: (mm) => isMm ? +mm.toFixed(1) : +(mm / 1000).toFixed(4),
    fromDisplay: (v) => isMm ? v : v * 1000,
    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
  };
}

function SheetExportMenu({ sheet, editorDispatch }) {
  const [open, setOpen] = useState(false);
  const rootRef = useRef(null);
  const pngOptions = [
    { label: 'PNG 150 DPI', dpi: 150 },
    { label: 'PNG 300 DPI', dpi: 300 },
    { label: 'PNG 600 DPI', dpi: 600 },
  ];

  useEffect(() => {
    if (!open) return undefined;

    const handleMouseDown = (event) => {
      if (rootRef.current && !rootRef.current.contains(event.target)) {
        setOpen(false);
      }
    };

    document.addEventListener('mousedown', handleMouseDown);
    return () => document.removeEventListener('mousedown', handleMouseDown);
  }, [open]);

  const handleExport = async (kind, options = {}) => {
    if (!sheet) return;
    try {
      if (kind === 'pdf') {
        await exportActiveSheetAsPdf(
          sheet.title || sheet.drawingName || 'sheet',
          sheet.paperSize
        );
        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Exported sheet as PDF.' });
      } else {
        await exportActiveSheetAsPng(
          sheet.title || sheet.drawingName || 'sheet',
          options
        );
        const dpiLabel = options.dpi ? ` (${options.dpi} DPI)` : '';
        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: `Exported sheet as PNG${dpiLabel}.` });
      }
    } catch (error) {
      editorDispatch({
        type: 'SET_STATUS_MESSAGE',
        message: error.message || `${kind.toUpperCase()} export failed.`,
      });
    } finally {
      setOpen(false);
    }
  };

  return (
    <div className={styles.exportMenu} ref={rootRef}>
      <button
        className={styles.exportMenuTrigger}
        type="button"
        onClick={() => setOpen((value) => !value)}
      >
        Export sheet
        <span className={styles.exportMenuChevron}>{open ? '▴' : '▾'}</span>
      </button>
      {open && (
        <div className={styles.exportMenuList}>
          <button
            className={styles.exportMenuItem}
            type="button"
            onClick={() => handleExport('pdf')}
          >
            PDF
          </button>
          {pngOptions.map((option) => (
            <button
              key={option.dpi}
              className={styles.exportMenuItem}
              type="button"
              onClick={() => handleExport('png', { dpi: option.dpi })}
            >
              {option.label}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

