          onChange={(e) => updateSource(e.target.value)}
          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
        >
          <option value="plan">Plan</option>
